);

    reg [5:0] sec, min;
    reg [4:0] hour;
    always @(posedge clk) begin
        if (rst) begin sec <= 0; min <= 0; hour <= 0; end
        else begin
            if (sec == 59) begin
                sec <= 0;
                if (min == 59) begin min <= 0; hour <= hour + 1; end
                else min <= min + 1;
            end else sec <= sec + 1;
        end
    end
