    input               clk ,
    input               rst ,
    input               sw  ,
    input               k   ,

    output  reg [7:0]   led
    );

    reg [31:0] cnt;
    reg [1:0] mode;
    always @(posedge clk) begin
        if (rst) begin cnt <= 0; led <= 8'b00000001; end
        else begin
            if (cnt == 49999999) begin
                cnt <= 0;
                case (mode)
                    2'd0: led <= {led[6:0], led[7]};
                    2'd1: led <= {led[0], led[7:1]};
                    default: led <= {led[6:0], led[7]};
                endcase
            end else cnt <= cnt + 1;
        end
    end

endmodule

